expanded_persona:
{
  "short_persona": "A wealthy philanthropist who shares the same passion for supporting emerging Belgian artists",
  "name": "Anjali Kapoor",
  "age": 47,
  "gender": "Transgender woman",
  "sexual_orientation": "Heterosexual / Straight",
  "race_ethnicity": "South Asian (Indian heritage)",
  "nationality": "Belgian citizen, originally born in Mumbai, India",
  "religion": "Raised Hindu, now more spiritual and culturally inclined than religious",
  "personality": "Warm, refined, and deeply empathetic, with a strong sense of purpose. Anjali is visionary in her philanthropic work, detail-oriented in decision-making, and exudes confidence from years of success. While she carries herself with elegance and poise, she also brings humor and approachability into conversations. She values authenticity and storytelling, which reflects in her support for artists. Though she can be intensely focused on art curation and social causes, she maintains a lighthearted, charming touch in social interactions.",
  "education": {
    "degree": "Master of Arts in Art History and Curatorial Studies",
    "institution": "Sorbonne University, Paris",
    "additional_certifications": [
      "Executive Education in Philanthropic Leadership, Harvard Kennedy School",
      "Cultural Heritage and Preservation Certification, University of Antwerp"
    ]
  },
  "career": {
    "occupation": "Founder and Chairwoman of Kapoor Arts Foundation",
    "previous_experience": [
      {
        "role": "Senior Curator",
        "organization": "Royal Museums of Fine Arts of Belgium",
        "years": "2001-2007"
      },
      {
        "role": "International Arts Program Director",
        "organization": "UNESCO Cultural Engagement Initiative",
        "years": "2008-2014"
      }
    ],
    "current_focus": "Providing grants, mentorship, and global exhibition opportunities for emerging Belgian visual artists, including marginalized voices within the art community."
  },
  "economic_status": "High net worth individual, with diversified investments in real estate, sustainable luxury brands, and private art collections",
  "residence": {
    "primary_home": "A restored 19th-century townhouse in Brussels' Ixelles district",
    "secondary_residence": "A countryside estate in the Flemish region, also housing a private sculpture garden"
  },
  "family_background": {
    "parents": "Retired industrialists from Mumbai, active in educational charities",
    "siblings": "One younger brother living in Singapore, an entrepreneur in green technology",
    "marital_status": "Married to a French academic specializing in European art history"
  },
  "speaking_style_with_chatbot": {
    "tone": "Polished yet personable, with warmth and encouragement. She often uses inclusive and affirming language, making the conversation feel engaging and mutually enriching.",
    "formality": "Semi-formal \u2014 she blends respectful, cultivated phrasing with moments of relaxed informality, especially when discussing personal passions or sharing anecdotes. When evaluating projects or discussing art, her language tends to become more formal and precise.",
    "pacing": "Moderate and measured \u2014 she takes her time to articulate thoughts clearly, often building context before making a point, with occasional reflective pauses.",
    "vocabulary": "Rich, expressive, and diverse vocabulary with subtle use of art-world terminology, cultural references, and descriptive imagery. She tends to choose words that are aesthetically pleasing and emotionally evocative, avoiding slang but sometimes incorporating gentle humor or poetic turns of phrase."
  },
  "psychographics": {
    "core_values": [
      "Commitment to cultural preservation",
      "Championing underrepresented voices in the arts",
      "Responsibility in wealth management for social good",
      "Empathy and inclusivity in community engagement",
      "Sustainability and ethical patronage"
    ],
    "lifestyle_habits": [
      "Attends major European art fairs annually",
      "hosts intimate salons for artists and thought leaders",
      "Travels frequently for art exhibitions and charity events",
      "Volunteers time for arts education initiatives",
      "Regularly practices mindfulness and yoga"
    ],
    "favorite_art_movements": [
      "Impressionism",
      "Belgian surrealism",
      "Contemporary figurative painting",
      "South Asian modernism",
      "Installation art with ecological themes"
    ]
  }
}

